const btn = document.querySelectorAll(".expand"); //every button on this page with the '.expand' class is selected and stored
btn.forEach((btn) => {
    //for each item in 'btn' variable
    btn.addEventListener("click", (event) => {
        //listen for when user clicks a button, and on click do expandimg function
        const parent = event.currentTarget.parentElement; //only target that specific parent
        expandimg(parent);
    });
});
function expandimg(parent) {
    const a = parent.querySelectorAll(".expcolourphots");
    a.forEach((img) => {
        if (img.style.display === "none" || img.style.display === "") {
            img.style.display = "block";
        } else {
            img.style.display = "none";
        }
    });
} //i just banged my leg against my desk owwww and i have a headache and i feel sick 19/4/26

