function activeVisibility(activeView) {
    calendarTypePerSpecies.style.display = activeView === "calendarTypePerSpecies" ? "block" : "none";
    calendarTypePerMonth.style.display = activeView === "calendarTypePerMonth" ? "block" : "none";
    calendarPerMonthAsleep.style.display = activeView === "calendarPerMonthAsleep" ? "block" : "none";

    perMonthBtns.style.display = activeView !== "calendarTypePerSpecies" ? "" : "none";
    perSpeciesBtns.style.display = activeView === "calendarTypePerSpecies" ? "" : "none";
} //checks if upcoming display matches newly defined variable 'activeview' and since buttons are never there at the same time always makes sure monthbtns is hidden when speciesbtns is shown
function toggleType() {
    if (toggledVisibilityCheck(calendarTypePerSpecies)) {
        activeVisibility("calendarTypePerMonth");
    } else if (toggledVisibilityCheck(calendarTypePerMonth) || toggledVisibilityCheck(calendarPerMonthAsleep)) {
        activeVisibility("calendarTypePerSpecies");
    } else {
        activeVisibility("calendarTypePerMonth");
    }
}
function toggleAsleep() {
    if (toggledVisibilityCheck(calendarTypePerMonth)) {
        activeVisibility("calendarPerMonthAsleep");
    } else {
        activeVisibility("calendarTypePerMonth");
    }
}
